def normalize_step(step, index):
    """Normalize a single step object."""
    if not isinstance(step, dict):
        raise ETLValidationError(
            "SCHEMA_VALIDATION_FAILED",
            "ETL_ERROR: Step must be an object",
            f"pipeline.steps[{index}]"
