        if not col.strip():
            raise ETLValidationError(
                "SCHEMA_VALIDATION_FAILED",
                f"ETL_ERROR: column[{i}] cannot be empty or whitespace",
                f"pipeline.steps[{index}].columns[{i}]"
            )
