#!/usr/bin/env python3
"""Test script for call sub-pipeline feature."""

import json
import subprocess
import sys

def run_pipeline(request):
    """Run the ETL pipeline with the given request JSON."""
    result = subprocess.run(
        ['python', 'etl_pipeline.py', '--execute'],
        input=json.dumps(request),
        capture_output=True,
        text=True
    )
    return json.loads(result.stdout)

def test_basic_call_with_params():
    """Test 1: Basic call with parameters."""
    request = {
        "defs": {
            "Normalize": { "steps":[
                {"op":"map","as":"z","expr":"(value - params.mean) / params.std"}
            ]},
            "KeepCols": { "steps":[
                {"op":"select","columns":["id","z"]}
            ]}
        },
        "pipeline": {
            "steps": [
                {"op":"call","name":"Normalize","params":{"mean":100,"std":20}},
                {"op":"call","name":"KeepCols","params":{}}
            ]
        },
        "dataset":[
            {"id":1,"value":120},
            {"id":2,"value":80}
        ]
    }

    output = run_pipeline(request)

    expected = {
        "status": "ok",
        "data": [
            {"id": 1, "z": 1.0},
            {"id": 2, "z": -1.0}
        ],
        "metrics": {"rows_in": 2, "rows_out": 2}
    }

    # Check status
    assert output["status"] == expected["status"], f"Expected status 'ok', got {output.get('status')}"

    # Check data
    assert len(output["data"]) == len(expected["data"]), f"Expected {len(expected['data'])} rows, got {len(output['data'])}"
    for i, row in enumerate(output["data"]):
        for key in expected["data"][i]:
            assert row[key] == expected["data"][i][key], f"Row {i}, key {key}: expected {expected['data'][i][key]}, got {row[key]}"

    # Check metrics
    assert output["metrics"]["rows_in"] == expected["metrics"]["rows_in"], f"Expected rows_in {expected['metrics']['rows_in']}, got {output['metrics'].get('rows_in')}"
    assert output["metrics"]["rows_out"] == expected["metrics"]["rows_out"], f"Expected rows_out {expected['metrics']['rows_out']}, got {output['metrics'].get('rows_out')}"

    print("Test 1 (Basic call with parameters): PASSED")
    return True

def test_missing_definition():
    """Test 2: Missing definition."""
    request = {
        "defs": {},
        "pipeline": { "steps": [ {"op":"call","name":"Missing","params":{}} ] },
        "dataset":[{"id":1}]
    }

    output = run_pipeline(request)

    expected = {
        "status": "error",
        "error_code": "UNKNOWN_DEF",
        "path": "defs[Missing]"
    }

    assert output["status"] == expected["status"], f"Expected status 'error', got {output.get('status')}"
    assert output["error_code"] == expected["error_code"], f"Expected error_code '{expected['error_code']}', got {output.get('error_code')}"
    assert output["path"] == expected["path"], f"Expected path '{expected['path']}', got {output.get('path')}"

    print("Test 2 (Missing definition): PASSED")
    return True

def test_direct_recursion():
    """Test 3: Direct recursion."""
    request = {
        "defs": {
            "Loop": { "steps":[{"op":"call","name":"Loop","params":{}}] }
        },
