    }

    assert output["status"] == expected["status"], f"Expected status 'error', got {output.get('status')}"
    assert output["error_code"] == expected["error_code"], f"Expected error_code '{expected['error_code']}', got {output.get('error_code')}"
    assert output["path"] == expected["path"], f"Expected path '{expected['path']}', got {output.get('path')}"

