def test_call_with_empty_params():
    """Test 4: Call with empty params."""
    request = {
        "defs": {
            "Identity": { "steps": [
                {"op":"map","as":"doubled","expr":"value * params.factor"}
            ]}
        },
        "pipeline": {
            "steps": [
                {"op":"call","name":"Identity","params":{"factor":2}}
            ]
        },
