def test_indirect_recursion():
    """Test 5: Indirect recursion (A calls B which calls A)."""
    request = {
        "defs": {
            "A": { "steps":[{"op":"call","name":"B","params":{}}] },
            "B": { "steps":[{"op":"call","name":"A","params":{}}] }
