def test_nested_calls():
    """Test 6: Nested calls with different params."""
    request = {
        "defs": {
            "AddOffset": { "steps":[
                {"op":"map","as":"value","expr":"value + params.offset"}
            ]},
            "Transform": { "steps":[
                {"op":"call","name":"AddOffset","params":{"offset":100}}
            ]}
        },
        "pipeline": {
            "steps": [
                {"op":"call","name":"Transform","params":{"offset":0}}
            ]
        },
