            {"id":1,"value":5}
        ]
    }

    output = run_pipeline(request)

    assert output["status"] == "ok", f"Expected status 'ok', got {output.get('status')}"
    # The Transform call doesn't pass offset to AddOffset, so AddOffset gets its own offset=100
    # Starting value is 5, Transform doesn't change it (offset=0), then AddOffset adds 100
    # Result should be 105
    assert output["data"][0]["value"] == 105, f"Expected value 105, got {output['data'][0].get('value')}"

