                if self.pos >= len(self.tokens):
                    raise ETLEvaluationError(
                        "BAD_EXPR",
                        "ETL_ERROR: Expected member name after 'params.'",
                        ""
                    )
                member_type, member_name = self.tokens[self.pos]
                if member_type != "IDENTIFIER":
                    raise ETLEvaluationError(
                        "BAD_EXPR",
                        "ETL_ERROR: Expected identifier after 'params.'",
                        ""
                    )
                self.pos += 1
                if self._params is not None:
                    return self._params.get(member_name)
                return None
        return row.get(value)
    else:
        raise ETLEvaluationError(
            "BAD_EXPR",
            f"ETL_ERROR: Unexpected token '{value}'",
            ""
        )

